.darma-loader-darma-custom-609 {color: var(--loader-color, #4f46e5);
   width: 82px;
   aspect-ratio: 1;
   padding: 10px;
   box-sizing: border-box;
   display: grid;
   background: currentColor;
   filter: blur(3px) contrast(7) hue-rotate(290deg);
   mix-blend-mode: darken;
}
.darma-loader-darma-custom-609:before {
  content: "";
   margin: auto;
   width: 30px;
   height: 30px;
   border-radius: 50%;
   color: #ff0000;
   background: currentColor;
   box-shadow: -30px 0,30px 0,0 30px, 0 -30px;
   animation: darma-loader-darma-custom-609-l6 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-609-l6 {
  90%,100% {box-shadow: -10px 0,10px 0,0 10px, 0 -10px;
  transform: rotate(180deg)}
}

